import{_ as t,b as n,e as a,al as o}from"./chunks/framework.DrQIcdFj.js";(function(){try{var i=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};i.SENTRY_RELEASE={id:"abf23ae41d8e9798d1084c6d3fd2516340828177"};var s=new i.Error().stack;s&&(i._sentryDebugIds=i._sentryDebugIds||{},i._sentryDebugIds[s]="1cb71597-4129-4057-bcfa-7f5979b47a29",i._sentryDebugIdIdentifier="sentry-dbid-1cb71597-4129-4057-bcfa-7f5979b47a29")}catch{}})();const g=JSON.parse('{"title":"CSS继承(Inheritance)","description":"","frontmatter":{},"headers":[],"relativePath":"css/basic/inheritance.md","filePath":"css/basic/inheritance.md","lastUpdated":null}'),r={name:"css/basic/inheritance.md"};function l(i,s,e,p,d,h){return n(),a("div",null,[...s[0]||(s[0]=[o(`<h1 id="css继承-inheritance" tabindex="-1">CSS继承(Inheritance) <a class="header-anchor" href="#css继承-inheritance" aria-label="Permalink to &quot;CSS继承(Inheritance)&quot;">​</a></h1><p>CSS 继承是 CSS 中一个非常重要但常被忽视的机制。</p><p>它的核心概念很简单：有些属性，如果你不显式地给子元素设置，子元素会自动“继承”父元素的这个属性值。 但这并不是全部。为了让你彻底搞懂继承，我们需要明确两个关键点：哪些属性会继承 以及 如何强制控制继承。</p><h2 id="_1-哪些属性会继承-the-inherited-properties" tabindex="-1">1. 哪些属性会继承？ (The &quot;Inherited&quot; Properties) <a class="header-anchor" href="#_1-哪些属性会继承-the-inherited-properties" aria-label="Permalink to &quot;1. 哪些属性会继承？ (The &quot;Inherited&quot; Properties)&quot;">​</a></h2><p>并不是所有 CSS 属性都会继承。CSS 属性大致可以分为两类：</p><h3 id="_1-1-可继承属性-inherited-properties" tabindex="-1">1.1 可继承属性 (Inherited Properties) <a class="header-anchor" href="#_1-1-可继承属性-inherited-properties" aria-label="Permalink to &quot;1.1 可继承属性 (Inherited Properties)&quot;">​</a></h3><p>这些属性通常与 文本内容 和 排版 相关。逻辑是：如果你设置了整个段落的字体颜色，通常你也希望段落里的强调文本 <code>&lt;em&gt;</code> 也是这个颜色。</p><p><strong>文本系列:</strong></p><ul><li><p><strong><code>color</code></strong> (颜色)</p></li><li><p><strong><code>direction</code></strong> (文本方向)</p></li><li><p><strong><code>line-height</code></strong> (行高)</p></li><li><p><strong><code>text-align</code></strong> (文本对齐)</p></li><li><p><strong><code>text-indent</code></strong> (首行缩进)</p></li><li><p><strong><code>text-transform</code></strong> (文本大小写转换)</p></li><li><p><strong><code>letter-spacing</code></strong> (字间距)</p></li><li><p><strong><code>word-spacing</code></strong> (词间距)</p></li><li><p><strong><code>white-space</code></strong> (空白处理)**</p></li></ul><p><strong>字体系列:</strong></p><ul><li><p><strong><code>font</code></strong> (简写)</p></li><li><p><strong><code>font-family</code></strong> (字体族)</p></li><li><p><strong><code>font-size</code></strong> (字体大小)</p></li><li><p><strong><code>font-style</code></strong> (字体样式)</p></li><li><p><strong><code>font-weight</code></strong> (字体粗细)</p></li></ul><p><strong>其他:</strong></p><ul><li><p><strong><code>visibility</code></strong> (可见性 - 注意：opacity 不继承)</p></li><li><p><strong><code>cursor</code></strong> (鼠标光标)</p></li><li><p><strong><code>list-style</code></strong> (列表样式)</p></li></ul><h3 id="_1-2-不可继承属性-non-inherited-properties" tabindex="-1">1.2 不可继承属性 (Non-inherited Properties) <a class="header-anchor" href="#_1-2-不可继承属性-non-inherited-properties" aria-label="Permalink to &quot;1.2 不可继承属性 (Non-inherited Properties)&quot;">​</a></h3><p>这些属性通常与 盒模型、布局 和 背景 相关。逻辑是：如果你给父元素加了一个红色的边框，你肯定不希望里面的所有子元素也都自动带上红色边框。</p><ul><li><p>盒模型: <strong><code>width</code></strong>, <strong><code>height</code></strong>, <strong><code>margin</code></strong>, <strong><code>padding</code></strong>, <strong><code>border</code></strong></p></li><li><p>背景: <strong><code>background</code></strong> (背景色、背景图等)</p></li><li><p>定位: <strong><code>position</code></strong>, <strong><code>top</code></strong>, <strong><code>left</code></strong>, <strong><code>right</code></strong>, <strong><code>bottom</code></strong>, <strong><code>z-index</code></strong>, <strong><code>float</code></strong></p></li><li><p>显示: <strong><code>display</code></strong>, <strong><code>overflow</code></strong>, <strong><code>vertical-align</code></strong></p></li></ul><h2 id="_2-如何控制继承-controlling-inheritance" tabindex="-1">2. 如何控制继承？ (Controlling Inheritance) <a class="header-anchor" href="#_2-如何控制继承-controlling-inheritance" aria-label="Permalink to &quot;2. 如何控制继承？ (Controlling Inheritance)&quot;">​</a></h2><p>CSS 提供了四个特殊的关键字，允许你强制改变任何属性的继承行为。这些关键字可以用在任何 CSS 属性上。</p><h3 id="_2-1-inherit-强制继承" tabindex="-1">2.1 <code>inherit</code> (强制继承) <a class="header-anchor" href="#_2-1-inherit-强制继承" aria-label="Permalink to &quot;2.1 \`inherit\` (强制继承)&quot;">​</a></h3><p><strong>作用:</strong> 强制让子元素的某个属性值等于父元素的该属性值（即使这个属性默认是不继承的）。</p><p><strong>场景:</strong> 你想让子元素的边框颜色和父元素完全一致。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 子元素也会有 1px solid red 的边框 */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.parent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  border</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> solid</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.child</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  border</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">inherit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_2-2-initial-重置为默认值" tabindex="-1">2.2 <code>initial</code> (重置为默认值) <a class="header-anchor" href="#_2-2-initial-重置为默认值" aria-label="Permalink to &quot;2.2 \`initial\` (重置为默认值)&quot;">​</a></h3><p><strong>作用:</strong> 将属性重置为 CSS 规范中定义的初始默认值（浏览器的默认样式），完全忽略继承。</p><p><strong>场景:</strong> 父元素设置了红色字体，但你希望某个子元素恢复为浏览器默认的黑色字体。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 变回黑色 (浏览器默认值) */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.parent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.child</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">initial</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_2-3-unset-恢复自然状态" tabindex="-1">2.3 <code>unset</code> (恢复自然状态) <a class="header-anchor" href="#_2-3-unset-恢复自然状态" aria-label="Permalink to &quot;2.3 \`unset\` (恢复自然状态)&quot;">​</a></h3><p><strong>作用:</strong> 这是一个智能的关键字。</p><ul><li><p>如果该属性是可继承的（如 color），它就表现得像 <code>inherit</code>。</p></li><li><p>如果该属性是不可继承的（如 border），它就表现得像 <code>initial</code>。</p></li></ul><p><strong>场景:</strong> 当你清理样式时，<code>unset</code> 是最安全的“重置”方式。</p><h3 id="_2-4-revert-回归浏览器-用户样式" tabindex="-1">2.4 <code>revert</code> (回归浏览器/用户样式) <a class="header-anchor" href="#_2-4-revert-回归浏览器-用户样式" aria-label="Permalink to &quot;2.4 \`revert\` (回归浏览器/用户样式)&quot;">​</a></h3><p><strong>作用:</strong> 将样式回滚到浏览器默认样式表（User Agent Stylesheet）中定义的值。它比 <code>initial</code> 更温和，因为它保留了浏览器默认的样式（比如 h1 的默认粗体和大字号），而 <code>initial</code> 可能会把 h1 变成普通文本大小。</p><h2 id="_3-常见误区与注意点" tabindex="-1">3. 常见误区与注意点 <a class="header-anchor" href="#_3-常见误区与注意点" aria-label="Permalink to &quot;3. 常见误区与注意点&quot;">​</a></h2><p><code>&lt;a&gt;</code> 标签的颜色:</p><p><strong>很多人问：</strong>“为什么我给 body 设置了 color: red，链接 <code>&lt;a&gt;</code> 却还是蓝色的？”</p><p><strong>原因:</strong> 浏览器默认样式表（User Agent Stylesheet）给 a 标签明确设置了 color: -webkit-link（蓝色）。因为具体选择器的优先级高于继承，所以继承下来的红色被浏览器的默认蓝色覆盖了。</p><p><strong>解决:</strong></p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">inherit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong><code>height: 100%</code> 不是继承:</strong></p><p>给子元素设置 <code>height: 100%</code> 并不是继承，而是计算。它是基于包含块（containing block）的高度来计算自己的高度。如果父元素高度是 auto，子元素的 100% 可能无效。</p><p><strong><code>opacity</code> 的“伪继承”:</strong></p><p><code>opacity</code> 属性本身是不继承的。但是，如果你给父元素设置了 <code>opacity: 0.5</code>，子元素看起来也会变透明。这不是继承，而是因为子元素是渲染在父元素这个“半透明层”之上的。你无法通过在子元素上设置 <code>opacity: 1</code> 来抵消父元素的透明度。</p><h2 id="_4-总结" tabindex="-1">4. <strong>总结</strong> <a class="header-anchor" href="#_4-总结" aria-label="Permalink to &quot;4. **总结**&quot;">​</a></h2><ul><li><p>文字排版类属性（color, font...）大多会继承。</p></li><li><p>盒子模型类属性（border, padding...）大多不会继承。</p></li><li><p>使用 <code>inherit</code> 关键字可以强制开启继承。</p></li><li><p>使用 <code>initial</code> 或 <code>unset</code> 可以切断继承。</p></li></ul>`,44)])])}const k=t(r,[["render",l]]);export{g as __pageData,k as default};
